// ---- Blueprint script functions ----
#define AFN_BP_COUNT 2
#define AFN_BP_INSTANCE_COUNT 1

static inline void afn_bp0_start() {
    afn_play_anim = 0;
    afn_gravity = 23;
    afn_auto_orbit_speed = 205;
}
static inline void afn_bp0_key_held() {
  {
    if (key_is_down(KEY_LEFT)) afn_input_right -= 256;
    if (key_is_down(KEY_DOWN)) afn_input_fwd -= 256;
    if (key_is_down(KEY_UP)) afn_input_fwd += 256;
    if (key_is_down(KEY_RIGHT)) afn_input_right += 256;
  }
  {
    if (key_is_down(KEY_R)) orbit_angle += 512;
    if (key_is_down(KEY_L)) orbit_angle -= 512;
  }
  if (key_is_down(KEY_B)) {
    afn_move_speed = 53;
    afn_play_anim = 0;
  }
}
static inline void afn_bp0_key_pressed() {
  if (key_hit(KEY_A)) {
    if (player_on_ground) player_vy = 486;
  }
}
static inline void afn_bp0_key_released() {
  if (key_released(KEY_A)) {
    if (player_vy > 0) player_vy = (player_vy * 51) >> 8;
  }
}
static inline void afn_bp0_update() {
    afn_move_speed = 35;
}
static inline void afn_bp0_collision() {
}

static inline void afn_bp1_start() {
}
static inline void afn_bp1_key_held() {
}
static inline void afn_bp1_key_pressed() {
}
static inline void afn_bp1_key_released() {
}
static inline void afn_bp1_update() {
}
static inline void afn_bp1_collision() {
    afn_pending_scene = 1;
    afn_pending_scene_mode = 0;
}

