    afn_bp_instances[1] = {
    {0, -1, {0}},
};

static inline void afn_bp_dispatch_start(void) {
  for (int i = 0; i < 1; i++) {
    switch (afn_bp_instances[i].bpIdx) {
    case 0: afn_bp0_start(); break;
    case 1: afn_bp1_start(); break;
    }
  }
}
